# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, name, balance=0):
        self.name = name
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            print("Invalid deposit amount")
            return False

    def withdraw(self, amount):
        if amount > 0 and amount <= self.balance:
            self.balance -= amount
            return True
        elif amount > self.balance:
            print("Insufficient balance for withdrawal")
            return False
        else:
            print("Invalid withdrawal amount")
            return False

    def get_balance(self):
        return self.balance

transactions = {
    "Alice": Account("Alice"),
    "Bob": Account("Bob"),
}

def process_transaction(sender, receiver, amount):
    if sender in transactions and receiver in transactions:
        sender_account = transactions[sender]
        receiver_account = transactions[receiver]
        if sender_account.withdraw(amount) and receiver_account.deposit(amount):
            print(f"Successfully transferred {amount} from {sender} to {receiver}")
        else:
            print("Transaction failed")
    else:
        print("Invalid accounts specified for transaction")